mapper.select:
SELECT u.*, r.role_code FROM user u INNER JOIN user_role ur ON u.id = ur.user_id INNER JOIN role r ON ur.role_id = r.id WHERE r.role_code = #{roleCode}
AND ( u.username LIKE CONCAT('%', #{keyword}, '%') OR u.real_name LIKE CONCAT('%', #{keyword}, '%') OR u.student_no LIKE CONCAT('%', #{keyword}, '%') OR u.teacher_no LIKE CONCAT('%', #{keyword}, '%') )
AND u.status = #{status}
ORDER BY u.create_time DESC
